import{c as a,Q as i,j as e,m as s}from"./chunks/framework.BXc4yaFE.js";const S=JSON.parse('{"title":"每个小白和达人必看！一次设置，永久生效：Claude Skills 从入门到精通最佳实战经验！ — @berryxia","description":"","frontmatter":{"title":"每个小白和达人必看！一次设置，永久生效：Claude Skills 从入门到精通最佳实战经验！ — @berryxia","author":"Berryxia.AI（@berryxia）","date":"2026-03-26T00:00:00.000Z","source":"https://x.com/berryxia/status/2037186792991117336","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-26-@berryxia-117336.md","filePath":"research/tweets/2026-03-26-@berryxia-117336.md","lastUpdated":1779898012000}'),t={name:"research/tweets/2026-03-26-@berryxia-117336.md"};function n(r,l,o,k,d,p){return i(),e("div",null,[...l[0]||(l[0]=[s(`<h1 id="每个小白和达人必看-一次设置-永久生效-claude-skills-从入门到精通最佳实战经验-—-berryxia" tabindex="-1">每个小白和达人必看！一次设置，永久生效：Claude Skills 从入门到精通最佳实战经验！ — @berryxia <a class="header-anchor" href="#每个小白和达人必看-一次设置-永久生效-claude-skills-从入门到精通最佳实战经验-—-berryxia" aria-label="Permalink to &quot;每个小白和达人必看！一次设置，永久生效：Claude Skills 从入门到精通最佳实战经验！ — @berryxia&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/berryxia/status/2037186792991117336" target="_blank" rel="noreferrer">https://x.com/berryxia/status/2037186792991117336</a><strong>作者</strong>：Berryxia.AI（@berryxia） <strong>發布日期</strong>：2026-03-26 <strong>收錄日期</strong>：2026-05-27（重新收錄，補全 1 個 MARKDOWN code block） <strong>類型</strong>：Twitter Article <strong>統計</strong>：419 likes · 79 retweets · 951 bookmarks · 126819 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>在这里感谢@aiedge_ on X (Twitter) 撰写和总结的如此好的文章，非常值得刚开始学习Claude Code的同学使用！</p><h2 id="你每天都在做这件事-却从没发现它有多浪费时间" tabindex="-1">你每天都在做这件事，却从没发现它有多浪费时间 <a class="header-anchor" href="#你每天都在做这件事-却从没发现它有多浪费时间" aria-label="Permalink to &quot;你每天都在做这件事，却从没发现它有多浪费时间&quot;">​</a></h2><p>[圖 1] 想象一下这样的早晨。 你打开 Claude，要写一篇公司博客。于是你开始打字：</p><blockquote><p>“我们是一家做 B2B SaaS 的公司，主要服务中小企业，语气要专业但不要太正式，受众是非技术背景的创业者，不要用‘赋能’‘生态’‘闭环’这些词，标题要具体不要抽象，段落不超过四句话……” 说完这些，Claude 终于理解了你是谁，对话才能正式开始。 第二天，你打开一个新对话，要写一封销售邮件。 “我们是一家做 B2B SaaS 的公司……” 你又开始打了。 这不是偶发状况，这是每一个重度使用 Claude 的人的日常。而且你可能根本没意识到，因为每一次解释都只要几分钟，看起来没什么大不了。 但问题来了： 📊 每天打开 5 个新对话 ⏱️ 每次花 3 分钟解释背景 📅 一周 = 105 分钟 🚨 一年 = 将近 90 小时 这 90 小时，全部用在了告诉 Claude “你是谁” 上面。 💡 Claude Skills 是这个问题最彻底的解法 不是优化解，是彻底消灭的解法。 @aiedge_ 运营着三家公司，在 2026 年 3 月的一篇文章里说： “如果这个月我在 X 上发的 200 多条内容里，你只能带走一件事，就带走 Skills。” 他不只是在用 Skills，他在每家公司的每个部门都强制要求大家构建并使用它们。 📖 这篇文章的内容： ✅ Skills 是什么 ✅ 怎么建 ✅ 怎么建好 ✅ Anthropic 在 2026 年 3 月刚推出的三个重要升级</p></blockquote><h2 id="什么是-claude-skills" tabindex="-1">什么是 Claude Skills <a class="header-anchor" href="#什么是-claude-skills" aria-label="Permalink to &quot;什么是 Claude Skills&quot;">​</a></h2><p>[圖 2] 一句话说清楚：Claude Skills 是把你的指令集打包成文件，随时调用的复用模块 技术上，它是一个 Markdown 文件，里面写着 Claude 完成某类任务需要知道的一切——你的身份、你的受众、你的标准、你的禁忌、什么叫好输出。你把这个文件上传到 Claude 账户，之后每次只需要一句话触发它：</p><blockquote><p>“用我的品牌音调 Skill，写一篇关于产品发布的 LinkedIn 帖子。” Claude 会自动调取文件里的全部上下文，产出的结果就像你已经把所有背景解释过一遍。但你什么都没有解释。 这背后有个值得仔细想的逻辑。Claude 本身的能力在不断进化，但大多数人的使用方式却停在原地——每次对话从空白开始，把 Claude 当临时工具使用，用完即扔。Skills 改变了这个模式。它把你的专业判断、工作偏好和操作标准固化成可调用的资产，让 Claude 不再是一个陌生的临时工，而是一个已经接受过充分培训的专职助理。 类比：就像一家餐厅的 SOP 手册。新厨师来了，不需要主厨每道菜都在旁边盯着教，手册里有食材比例、火候标准、摆盘规范。Skills 就是你给 Claude 写的 SOP。 可以构建 Skills 的任务几乎没有边界：</p></blockquote><ul><li>内容创作 - 品牌语气、文章结构、写作禁忌——每次写东西都调用</li><li>研究与分析 - 你习惯的分析框架、输出格式、信息来源偏好</li><li>语法与编辑 - 你不喜欢的句式、常见错误清单、审校标准</li><li>外联与销售 - 邮件模板、信息提炼方式、个性化策略</li><li>求职应聘 - 你的简历、经历亮点、自我定位叙述方式</li></ul><blockquote><p>💡 核心原则： 任何你会重复告诉 Claude 的事情，都值得变成一个 Skill。</p></blockquote><h2 id="四步构建你的第一个-skill" tabindex="-1">四步构建你的第一个 Skill <a class="header-anchor" href="#四步构建你的第一个-skill" aria-label="Permalink to &quot;四步构建你的第一个 Skill&quot;">​</a></h2><p>[圖 3] 整个过程不超过 30 分钟。你只做一次，但之后每天都在收益。 步骤 1: 启用 Skill-Creator 进入 Claude 账户的 Customize → Skills，找到并开启「Skill-Creator」。 这是 Anthropic 官方预置的一个特殊 Skill，它的唯一功能是帮你构建其他 Skills。为什么要有这个东西？因为构建一个高质量的 Skill 文件本身是有门槛的——你需要知道怎么组织信息、怎么写规则、怎么给出示例、怎么设置自查清单。Skill-Creator 内置了这套知识，引导你一步步完成。</p><blockquote><p>💡 类比： 用 Skill 造 Skill——有点像用机床制造机床。 步骤 2: 把你的需求告诉 Claude 启用 Skill-Creator 后，你可以直接说： “我想为【某项工作流】构建一个 Skill，帮我构建它。” 但如果你想构建一个真正高质量的 Skill，最好用一个结构化的提示词，把上下文尽量完整地给到 Claude：</p></blockquote><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你正在构建一个 Claude Skill——以 Markdown 格式保存的可复用指令集。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我的 Skill 用于：[描述任务，例如写 B2B 博客文章、审校语法、撰写销售邮件]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>以下是 Claude 完成此任务需要的上下文：</span></span>
<span class="line"><span>- 我的名字/品牌：[你的名字或公司名]</span></span>
<span class="line"><span>- 我的受众：[你在为谁写作/服务]</span></span>
<span class="line"><span>- 我的语气和风格：[正式/非正式、专业/亲切、简洁/详细……]</span></span>
<span class="line"><span>- 我的输出标准：[好的输出是什么样的，越具体越好]</span></span>
<span class="line"><span>- 需要避免的内容：[禁忌词汇、格式要求、常见错误……]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请用上述上下文，编写一个完整的 SKILL.md 文件，要求：</span></span>
<span class="line"><span>1. 以一行文字说明此 Skill 的功能</span></span>
<span class="line"><span>2. 定义 Skill 激活时 Claude 扮演的角色</span></span>
<span class="line"><span>3. 列出 Claude 必须遵守的具体规则（越具体越好）</span></span>
<span class="line"><span>4. 至少包含一个优质输出的真实示例</span></span>
<span class="line"><span>5. 以 Claude 在输出前自查的质量清单结尾（3-5 个问题）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>格式为标准 Markdown 文件，可直接保存并上传至 Claude Project。</span></span></code></pre></div><blockquote><p>⚠️ 关键细节： 你提供的上下文越具体，Skill 就越好用。笼统的“语气要专业”，不如“语气参考 Paul Graham 的文章风格：直接、不用废话、句子短”。 步骤 3: 保存到账户 Claude 构建完毕后，会输出一个 Markdown 文件（有时是 zip 包）。界面上有「Copy to Skills」按钮，点击即可保存到你的 Anthropic 账户。 同时强烈建议在本地建一个专用文件夹（比如 ~/Documents/Claude-Skills/），把所有 Skill 的 .md 文件都备份在里面。原因有两个：</p></blockquote><ul><li>方便日后手动编辑迭代</li><li>账户如果出问题，本地备份是你唯一的保障 一个花了几小时打磨出来的 Skill 文件，值得被认真对待。 步骤 4: 调用 回到 Customize → Skills → My Skills，确认新建的 Skill 已经处于启用状态。 之后在任何 Claude 对话里，只需要说：</li><li>“用我的品牌音调 Skill，写一封【主题】的通知邮件”</li><li>“用我的语法检查 Skill 审校这段文字”</li><li>“用我的研究 Skill，整理关于【话题】的核心观点” Skill 会被自动识别并加载，Claude 会按照文件里的所有指令行动。从此，你不需要再解释你是谁，不需要重复你的标准，不需要粘贴任何背景。</li></ul><h2 id="如何构建真正好用的-skill" tabindex="-1">如何构建真正好用的 Skill <a class="header-anchor" href="#如何构建真正好用的-skill" aria-label="Permalink to &quot;如何构建真正好用的 Skill&quot;">​</a></h2><p>[圖 4] 这是整篇文章最核心的部分。任何人都能构建一个 Skill，但一个真正好用的 Skill 和一个平庸的 Skill 之间，差距可以非常大。 💡 技巧 1: 反向提问，让 Claude 来引导你 大多数人一坐下来就开始往提示词里填内容，然后发现自己不知道该填什么——我的语气是什么？我的受众是谁？我的禁忌词有哪些？ 换一个角度： 你不需要自己想清楚该给什么信息。告诉 Claude：</p><blockquote><p>“我想构建一个 [X] Skill，请问我 10 到 50 个问题，帮助你更好地构建它。” Claude 会问你所有应该被问到的问题。这些问题本身就是一份清单——告诉你构建一个高质量 Skill 需要哪些信息。回答完这些问题，90% 的工作就完成了。 🔍 技巧 2: 反向发现，找你从没想到的场景 Skills 的另一个强大用法，不是解决你已知的重复问题，而是发现你没意识到自己在做重复事情的地方。 告诉 Claude: “基于你对我的了解，哪些工作流对我来说最适合构建成 Skill？” 如果你和 Claude 已经有过一段时间的对话历史，它对你的工作模式其实了解颇深，能给出相当有价值的建议。作者用这个方法发现了几个自己根本没想到的 Skill 应用场景。 🔄 技巧 3: 把现有对话直接转化成 Skill 这是整个 Skills 体系里最被低估的一个技巧。 如果你之前和 Claude 就某个话题深聊过很多次，那段对话记录本身就是最好的 Skill 原料。你不需要从头描述你的偏好——那些偏好已经隐藏在你们交互的每一条记录里。直接说： “把我们这段对话里的一切，转化成一个 Skill 文件。” 真实案例： 作者的语法检查 Skill 就是这样来的。他和 Claude 就语法偏好聊了几个月，积累了大量具体的反馈和细节。当他用这段对话生成 Skill 时，Claude 已经完整“理解”了他所有的偏好，一步到位生成了一个非常精准的文件。 ⭐ 技巧 4: 贴一个真实范例，胜过一百条规则 这是提升 Skill 质量最快的单一动作。 与其花时间写“语气要自然”“避免陈词滥调”“结构要清晰”这类泛泛的规则，不如把一篇你觉得真正完美的文章、一封你觉得极好的邮件，直接粘贴进 Skill 文件，附上一句话说明： “这是我想要的输出质量，以此为标准。” Claude 从一个具体的好例子里获取的信息，远比从十条描述性规则里获取的多。而且，你只有在看到真实输出的时候，才能真正说清楚“好”意味着什么——抽象描述往往是在偷懒。 🔁 技巧 5: 把第一稿当草稿，迭代三轮才满意 Claude 生成的第一版 Skill 通常是一个不错的起点，但不是终点。作者说他通常需要 三轮迭代 才会真正满意。 方法很简单： 认真读完第一版，把所有你觉得不对劲、太笼统、缺了什么的地方写下来，然后告诉 Claude 修改。第二版读完，继续挑问题，继续改。这个过程费时间，但不费精力——你只是在审阅和指出问题，Claude 来完成修改。 ✅ 技巧 6: 在 Skill 结尾加一个自查清单 每个 Skill 文件的最后，放三到五个 Claude 在生成输出前要问自己的问题：</p></blockquote><ul><li>这段输出符合指定的语气要求吗？</li><li>有没有出现禁忌词汇？</li><li>格式是否符合标准？</li><li>这个输出达到了示例的质量水平吗？ 这几个问题看起来微不足道，但它们会在每次输出之前强迫 Claude 做一次对照检查，相当于把你的质控流程内化进了 Skill 本身。 📖 技巧 7: 手动通读 Skill 文件 这是最枯燥的一步，但作者明确说“无论如何都要做”。拿出几分钟，从头到尾认真读一遍你的 Skill 文件。你会发现一些问题：</li><li>某条规则其实含糊不清</li><li>某段描述有歧义</li><li>某个细节 Claude 其实理解不了 这些东西在你“试用”Skill 的时候不一定会暴露，但在你手动阅读的时候会变得显而易见。</li></ul><blockquote><p>💎 价值： 这几分钟的人工投入，换来的是之后每次调用都不出错。</p></blockquote><h2 id="claude-skills-2-0-三个在-2026-年-3-月上线的重要升级" tabindex="-1">Claude Skills 2.0：三个在 2026 年 3 月上线的重要升级 <a class="header-anchor" href="#claude-skills-2-0-三个在-2026-年-3-月上线的重要升级" aria-label="Permalink to &quot;Claude Skills 2.0：三个在 2026 年 3 月上线的重要升级&quot;">​</a></h2><p>[圖 5] Anthropic 在这次更新里解决了三个长期以来困扰重度用户的核心问题。 1️⃣ 内置评估与测试：你终于能知道 Skill 是否真的在工作 这是三个更新里最实质性的一个。 之前的痛点：你构建了一个 Skill，用了几次，感觉还不错，就认为它在正常工作了。但“感觉不错”是非常不可靠的标准。如果某次模型更新微调了 Claude 的输出倾向，你的 Skill 可能已经失效了——但你根本不知道，直到某天一个实际交付物出了问题。 现在的解决方案： Skills 2.0 引入了在保存前测试的机制。你写几个真实场景下会用到的提示词，然后 Claude 用这些提示词运行两次——一次激活你的 Skill，一次不激活。两次输出都会按照你预先定义的 断言（assertions） 打分，然后并排显示在预览界面里，供你对比和评价。</p><blockquote><p>📌 什么是“断言”？ 你需要告诉系统什么叫“好输出”——比如“输出不能超过 200 字”、“必须包含数据来源”、“语气应该是对话式的”。系统会自动评估输出是否满足这些条件，并给出分数。 这意味着你在部署 Skill 之前，就已经知道它会产生什么样的结果。从“凭感觉”到“有依据”，是一个根本性的转变。 2️⃣ A/B 测试：改进 Skill 不再靠猜 你对一个 Skill 做了修改，加了一条规则，调整了一个措辞，改写了示例——你怎么知道这些改动真的有效？ 以前的方法：改完之后用一段时间，如果感觉变好了就留下，如果感觉没变就继续改。这基本上是在靠主观印象做决策。 现在你可以做 A/B 测试： 把原版和修改版对着相同的一组提示词各跑一遍，系统会把两个版本的输出并排呈现，让你直接对比。 💎 价值： 这对于维护长期使用的 Skill 来说尤其有价值。当你不确定某次改动是否真的提升了质量，测试数据会给你一个明确的答案。改版不再靠感觉，靠实验。 3️⃣ 触发词优化：解决“Skill 根本不响应”的问题 Skill 有一个经常被忽视但很关键的机制：触发。 你说“用我的品牌 Skill 写一篇帖子”，Claude 需要识别这句话里的意图，然后找到并加载对应的 Skill。如果你的 Skill 描述写得不够清晰，或者措辞和你的调用方式不匹配，Skill 就不会被触发——整个文件等于沉默地躺在那里。 这个问题比听起来更常见，尤其是当你有多个 Skill 的时候。Skills 2.0 引入了 自动触发优化：系统会自动重写并测试不同版本的 Skill 描述，测量每个版本在各种调用措辞下的触发成功率，最终找到一个最可靠的版本，整个过程自动完成。 使用方式： 在加载了目标 Skill 的 Claude 对话里，直接说：</p></blockquote><ul><li>“对这个 Skill 做评估”</li><li>“帮我 A/B 测试这两个版本”</li><li>“优化这个 Skill 的触发描述”</li></ul><h2 id="真实工作流-七种已经验证的-skill-类型" tabindex="-1">真实工作流：七种已经验证的 Skill 类型 <a class="header-anchor" href="#真实工作流-七种已经验证的-skill-类型" aria-label="Permalink to &quot;真实工作流：七种已经验证的 Skill 类型&quot;">​</a></h2><p>[圖 6] 作者在文章里展示了三种最常用的核心 Skill，并列出了更多值得构建的方向 📝 品牌音调 Skill 这是最基础、也最常被提到的一种。 包含内容：</p><ul><li>品牌的核心价值主张</li><li>目标受众画像</li><li>语气描述（用具体形容词，不用“专业”这种泛词）</li><li>禁忌词汇清单</li><li>几篇实际输出的范例</li><li>不同内容类型（博客/社媒/邮件）的特定规则 建好之后，每次写任何类型的内容都先调用它。你的所有输出会自然具备一致的品牌声音，不需要每次自己把控，也不需要校对修正。 📄 PDF 生成器 Skill 输入任何文本，输出格式整洁、结构清晰的 PDF。 包含内容：</li><li>布局规范（页眉页脚、字体大小、间距）</li><li>内容组织方式（是否需要目录、章节格式）</li><li>视觉风格（颜色、边距） 适合需要频繁生产报告、简报、提案的工作场景。 📋 文件摘要 Skill 粘贴任何文本，输出结构化摘要。不同于通用的“帮我总结一下”，一个专门的摘要 Skill 可以：</li><li>定义输出的格式（要点列表还是段落）</li><li>定义必须保留的信息类型（数据、结论、行动项）</li><li>定义长度控制规则</li></ul><blockquote><p>🎯 关键： 一致性是关键——每次摘要都按同一套标准输出。 🎓 ELI5 Skill（Explain Like I&#39;m 5） 把任何复杂话题翻译成普通人能理解的语言。粘贴一篇学术论文的摘要或者技术文档，触发 Skill，得到一段可以直接分享给非专业受众的解释。 Skill 里可以定义：</p></blockquote><ul><li>禁用词汇（不用术语）</li><li>类比风格（日常生活类比优先）</li><li>目标读者背景（“假设读者没有任何相关领域知识”） 💼 求职 Skill 这是个人效率场景里 ROI 最高的 Skill 之一。 预存内容：</li><li>完整简历</li><li>主要项目经历</li><li>核心技能描述</li><li>你对自己最有说服力的叙述方式 之后每次申请新职位，只需要提供职位描述，Claude 就能自动生成一封针对性极强的求职信——不是泛泛的模板，而是真正根据你的具体经历和对方的具体需求量身匹配的内容。 📚 学习 Skill 你吸收新知识有自己的方式：</li><li>有人需要类比</li><li>有人需要反例</li><li>有人需要先看结论再看过程 把这些偏好告诉 Skill，之后让 Claude 给你解释任何新概念时，它都会自动采用你最容易接受的方式呈现，而不是一种通用的教科书式解释。 💪 健康与健身 Skill 预存信息：</li><li>你的目标（增肌/减脂/提高耐力）</li><li>限制（膝盖受伤不能跑步）</li><li>偏好（不喜欢去健身房）</li><li>当前基础（能做 30 个俯卧撑） 之后任何时候需要训练计划或饮食建议，Skill 已经有了足够的背景，输出会比泛泛的建议精准得多。</li></ul><h2 id="工具与延伸资源" tabindex="-1">工具与延伸资源 <a class="header-anchor" href="#工具与延伸资源" aria-label="Permalink to &quot;工具与延伸资源&quot;">​</a></h2><p>[圖 7] 📚 官方文 Anthropic 的 Claude Skills 完整文档，包含 API 集成说明和 Skill 文件格式规范 🏪 SkillsMSP 一个第三方 Skill 市场，目前收录超过 50 万个 现成 Skill，可直接下载使用。</p><blockquote><p>⚠️ 安全提示： 注意只从有明确身份认证的创作者处下载，未经审核的文件存在安全风险。 💻 Awesome Claude Skills ComposioHQ 在 GitHub 维护的精选 Skill 列表，质量经过人工筛选，比市场平台更可信 📖 官方指南 PDF Anthropic 出品的《The Complete Guide to Building Skills for Claude》，是目前最系统的入门材料</p></blockquote><h2 id="问题还是那一个" tabindex="-1">问题还是那一个 <a class="header-anchor" href="#问题还是那一个" aria-label="Permalink to &quot;问题还是那一个&quot;">​</a></h2><p>[圖 8] 文章开头说，你每次打开新对话，Claude 什么都不知道。我们算了一笔账：每天 5 个对话，每次 3 分钟解释背景，一年将近 90 小时。 但这还只是时间的损耗。更隐性的代价是质量的不稳定。因为你每次“解释背景”的措辞都不一样，Claude 每次对你的理解也有细微偏差，输出结果因此上下浮动。今天写出来的东西和上周写出来的，风格可能有微妙的差异，不够像“同一个人的作品”。 Skills 解决的不只是效率问题，还是一致性问题。 一个构建好的 Skill 文件，里面存着你最精准的自我描述，每次被调用时都原原本本地呈现出来，没有误差，没有遗漏，不会因为你今天解释得没有昨天清楚而影响输出质量。 这是一次性的投入。你花半小时构建一个，它就一直在那里。不会健忘，不会懈怠，不会在第 50 次对话时突然忘记你不喜欢感叹号。 所以这个问题值得认真想一想：你现在工作里，最频繁重复的上下文是什么？ 那里，就是你第一个 Skill 应该落地的地方。 原文来源：@aiedge_ on X (Twitter) · 发布于 2026 年 3 月 25 日 中文撰写：@Berryxia.AI</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Skills 從入門到精通實戰：1 個 MARKDOWN code block 含完整 skill 結構模板（frontmatter + 觸發條件 + 執行步驟 + 輸出格式）</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li><strong>Skills 是 Claude Code 的「肌肉記憶」</strong>：技能讓重複性工作流一次定義、永久複用</li><li><strong>Skills 設計原則</strong>：明確的觸發詞（trigger）；確定的輸出形狀（output contract）；原子化步驟（每步可驗證）</li><li><strong>進階技巧</strong>：Skills 可以呼叫 Skills（巢狀技能）；Skills 可以有參數；使用 @file 引用外部文件</li><li><strong>完整 Skill 結構模板</strong>：1 個 MARKDOWN code block 示範標準 frontmatter + 執行步驟格式</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>1 個 MARKDOWN code block（完整 skill 結構模板）</li><li>Skill 命名慣例：verb-noun 格式（如 code-review / deploy-app）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li><strong>1 個 code block 偏少</strong>：文章主題是 Skills 實戰，但只有 1 個具體代碼示例</li><li><strong>觸發詞設計的 edge case</strong>：未討論觸發詞衝突（多個 skill 有相似觸發詞時如何選擇）</li><li><strong>巢狀 Skills 的 context 問題</strong>：skill 呼叫 skill 時的 context window 佔用和 token 成本未提及</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>直接可操作性</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>概念新穎度</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>可驗證性</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>技術細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>普適性</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.5/10</strong></td><td>8×0.3+7×0.2+6×0.2+6×0.15+8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：SKILL <strong>理由</strong>：依評分與內容類型決定</p>`,51)])])}const c=a(t,[["render",n]]);export{S as __pageData,c as default};
